sql:
SELECT name, best_squat_kg
FROM athletes
WHERE athlete_id = 1;

SELECT name
FROM athletes
WHERE age > (SELECT AVG(age) FROM athletes);

SELECT athletes.name || ' - ' || divisions.division_name AS 'Athlete - Division'
FROM athletes
INNER JOIN divisions ON athletes.division_id = divisions.division_id;

SELECT equipment_name
FROM equipment
WHERE equipment_id NOT IN (SELECT equipment_id FROM results);

SELECT * 
FROM registrations 
WHERE event_id = 1;

SELECT equipment_name 
FROM equipment 
WHERE equipment_id = (
  SELECT equipment_id 
  FROM athletes 
  WHERE total_kg = (
    SELECT MAX(total_kg) 
    FROM athletes
  )
);

SELECT athlete_id, name, best_squat_kg
FROM athletes
WHERE best_squat_kg = (SELECT MAX(best_squat_kg) FROM athletes);

